import{_ as a,c as t,o as n,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Démarrage rapide: Mise en route de Plannotator | plannotator","description":"Apprenez à démarrer rapidement avec Plannotator. Découvrez les fonctionnalités clés en 5 minutes et configurez le plugin Claude Code ou OpenCode.","frontmatter":{"title":"Démarrage rapide: Mise en route de Plannotator | plannotator","sidebarTitle":"Prise en main en 5 minutes","subtitle":"Démarrage rapide: Mise en route de Plannotator","description":"Apprenez à démarrer rapidement avec Plannotator. Découvrez les fonctionnalités clés en 5 minutes et configurez le plugin Claude Code ou OpenCode.","order":1},"headers":[],"relativePath":"fr/backnotprop/plannotator/start/index.md","filePath":"fr/backnotprop/plannotator/start/index.md"}'),o={name:"fr/backnotprop/plannotator/start/index.md"};function l(i,e,s,d,u,p){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="demarrage-rapide" tabindex="-1">Démarrage rapide <a class="header-anchor" href="#demarrage-rapide" aria-label="Permalink to &quot;Démarrage rapide&quot;">​</a></h1><p>Ce chapitre vous aide à utiliser Plannotator à partir de zéro. Vous découvrirez ce qu&#39;est Plannotator, les problèmes qu&#39;il peut résoudre, et vous configurerez l&#39;installation dans l&#39;AI Coding Agent que vous utilisez (Claude Code ou OpenCode).</p><h2 id="contenu-de-ce-chapitre" tabindex="-1">Contenu de ce chapitre <a class="header-anchor" href="#contenu-de-ce-chapitre" aria-label="Permalink to &quot;Contenu de ce chapitre&quot;">​</a></h2><div class="grid-cards"><h3 id="demarrage-rapide-1" tabindex="-1"><a href="./getting-started/">Démarrage rapide</a> <a class="header-anchor" href="#demarrage-rapide-1" aria-label="Permalink to &quot;[Démarrage rapide](./getting-started/)&quot;">​</a></h3><p>Découvrez les fonctionnalités clés et les cas d&#39;utilisation de Plannotator, et réalisez votre première expérience en 5 minutes. Convient à tous les nouveaux utilisateurs comme première leçon.</p><h3 id="installer-le-plugin-claude-code" tabindex="-1"><a href="./installation-claude-code/">Installer le plugin Claude Code</a> <a class="header-anchor" href="#installer-le-plugin-claude-code" aria-label="Permalink to &quot;[Installer le plugin Claude Code](./installation-claude-code/)&quot;">​</a></h3><p>Installez et configurez le plugin Plannotator dans Claude Code. Prend en charge deux méthodes: le système de plugins et le hook manuel, couvrant les configurations locales et distantes.</p><h3 id="installer-le-plugin-opencode" tabindex="-1"><a href="./installation-opencode/">Installer le plugin OpenCode</a> <a class="header-anchor" href="#installer-le-plugin-opencode" aria-label="Permalink to &quot;[Installer le plugin OpenCode](./installation-opencode/)&quot;">​</a></h3><p>Installez et configurez le plugin Plannotator dans OpenCode, en activant l&#39;outil <code>submit_plan</code> et la commande <code>/plannotator-review</code>.</p></div><h2 id="parcours-d-apprentissage" tabindex="-1">Parcours d&#39;apprentissage <a class="header-anchor" href="#parcours-d-apprentissage" aria-label="Permalink to &quot;Parcours d&#39;apprentissage&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Ordre recommandé</p><ol><li><strong>Lisez d&#39;abord <a href="./getting-started/">Démarrage rapide</a></strong> : Comprenez ce qu&#39;est Plannotator, ce qu&#39;il peut faire, et établissez une compréhension globale</li><li><strong>Choisissez ensuite un tutoriel d&#39;installation</strong> : Sélectionnez le guide d&#39;installation correspondant à l&#39;AI Coding Agent que vous utilisez <ul><li>Utilisation de Claude Code → <a href="./installation-claude-code/">Installer le plugin Claude Code</a></li><li>Utilisation d&#39;OpenCode → <a href="./installation-opencode/">Installer le plugin OpenCode</a></li></ul></li></ol></div><p>Une fois l&#39;installation terminée, vous pouvez commencer à utiliser Plannotator pour les revues de plan et les revues de code.</p><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, continuez à apprendre les <strong><a href="./../platforms/">Fonctionnalités de la plateforme</a></strong> pour maîtriser l&#39;utilisation complète des revues de plan et des revues de code:</p><ul><li>Bases de la revue de plan: approuver, rejeter, ajouter des commentaires</li><li>Annotation d&#39;images: joindre des captures d&#39;écran dans les plans et les annoter</li><li>Revue de code: visualiser les diffs Git et ajouter des commentaires au niveau des lignes</li></ul>',10)])])}const g=a(o,[["render",l]]);export{m as __pageData,g as default};
